// pdf-zone-editor.component.ts
import {
  Component, Input, Output, EventEmitter, inject, signal,
  computed, OnInit, AfterViewInit, ViewChild, ElementRef
} from '@angular/core';
import { CommonModule, DecimalPipe } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { DishOption, MenuArService, MenuPdf, MenuPdfZone } from '../../../services/Menu-PDF/menu-ar.service';

interface DrawRect { startX: number; startY: number; curX: number; curY: number; }

@Component({
  selector: 'app-menu-pdf-zone-editor',
  standalone: true,
  imports: [CommonModule, FormsModule, DecimalPipe],
  templateUrl: './pdf-zone-editor.component.html',
  styleUrl: './pdf-zone-editor.component.css'
})
export class MenuPdfZoneEditorComponent implements OnInit, AfterViewInit {
  @Input({ required: true }) pdf!: MenuPdf;
  @Input() dishes: DishOption[] = [];
  @Output() back = new EventEmitter<void>();
  @Output() zonesSaved = new EventEmitter<MenuPdfZone[]>();

  @ViewChild('pdfCanvas') canvasRef!: ElementRef<HTMLCanvasElement>;
  protected readonly Math = Math;

  private arService = inject(MenuArService);

  page      = signal(1);
  zoom      = signal(1.0);
  cw        = signal(0);
  ch        = signal(0);
  rendering = signal(false);
  zones     = signal<MenuPdfZone[]>([]);
  selId     = signal<string | null>(null);
  drawMode  = signal(false);
  drawing   = signal(false);
  rect      = signal<DrawRect | null>(null);
  query     = signal('');
  saving    = signal(false);
  feedback  = signal<string | null>(null);
  feedbackErr = signal(false);

  pageZones = computed(() => this.zones().filter(z => z.page_number === this.page()));
  selZone   = computed(() => this.zones().find(z => z.id === this.selId()) ?? null);

  filteredDishes = computed(() => {
    const q = this.query().toLowerCase().trim();
    if (!q) return this.dishes;
    return this.dishes.filter(d => d.name.toLowerCase().includes(q));
  });

  zoneCoords = computed(() => {
    const z = this.selZone();
    if (!z) return [];
    return [
      { label: 'x', val: Math.round(z.x) },
      { label: 'y', val: Math.round(z.y) },
      { label: 'w', val: Math.round(z.width) },
      { label: 'h', val: Math.round(z.height) },
    ];
  });

  rLeft = computed(() => { const r = this.rect(); return r ? Math.min(r.startX, r.curX) : 0; });
  rTop  = computed(() => { const r = this.rect(); return r ? Math.min(r.startY, r.curY) : 0; });
  rW    = computed(() => { const r = this.rect(); return r ? Math.abs(r.curX - r.startX) : 0; });
  rH    = computed(() => { const r = this.rect(); return r ? Math.abs(r.curY - r.startY) : 0; });

  zoomLabel = computed(() => Math.round(this.zoom() * 100) + '%');

  // ── Zoom methods (chiamati dal template, NO arrow fn inline) ──
  zoomIn()  { this.zoom.update(z => Math.min(3, z + 0.25)); }
  zoomOut() { this.zoom.update(z => Math.max(0.25, z - 0.25)); }

  // ── Mode toggles ──
  setSelectMode() { this.drawMode.set(false); }
  setDrawMode()   { this.drawMode.set(true); }

  // ── Deselect zone ──
  clearSel() { this.selId.set(null); }
  clearQuery() { this.query.set(''); }

  get modeHint(): string {
    return this.drawMode()
      ? 'Trascina sul PDF per creare una zona interattiva'
      : 'Clicca una zona per selezionarla e assegnare un piatto';
  }

  async ngOnInit() {
    this.zones.set(await this.arService.getZonesByPdf(this.pdf.id));
  }

  async ngAfterViewInit() { await this.renderPage(); }

  async prevPage() {
    if (this.page() <= 1) return;
    this.page.update(p => p - 1);
    await this.renderPage();
  }

  async nextPage() {
    if (this.page() >= this.pdf.page_count) return;
    this.page.update(p => p + 1);
    await this.renderPage();
  }

  private async renderPage() {
    if (!this.canvasRef) return;
    this.rendering.set(true);
    try {
      const r = await this.arService.renderPdfPage(this.pdf.pdf_url!, this.page(), 1.5);
      if (!r) return;
      this.cw.set(r.width);
      this.ch.set(r.height);
      await new Promise(res => setTimeout(res, 0));
      const ctx = this.canvasRef.nativeElement.getContext('2d')!;
      ctx.clearRect(0, 0, r.width, r.height);
      ctx.drawImage(r.canvas, 0, 0);
    } finally {
      this.rendering.set(false);
    }
  }

  onDown(e: MouseEvent) {
    if (!this.drawMode()) return;
    const p = this.pos(e);
    this.drawing.set(true);
    this.rect.set({ startX: p.x, startY: p.y, curX: p.x, curY: p.y });
  }

  onMove(e: MouseEvent) {
    if (!this.drawing()) return;
    const p = this.pos(e);
    this.rect.update(r => r ? { ...r, curX: p.x, curY: p.y } : null);
  }

  onUp(_e: MouseEvent) {
    if (!this.drawing()) return;
    this.drawing.set(false);
    if (this.rW() < 10 || this.rH() < 10) { this.rect.set(null); return; }
    const newZone: MenuPdfZone = {
      id: 'tmp_' + Date.now(),
      menu_pdf_id: this.pdf.id,
      dish_id: null,
      page_number: this.page(),
      x: this.rLeft(), y: this.rTop(),
      width: this.rW(), height: this.rH(),
      created_at: new Date().toISOString(),
    };
    this.zones.update(z => [...z, newZone]);
    this.selId.set(newZone.id);
    this.drawMode.set(false);
    this.rect.set(null);
  }

  onLeave() {
    if (this.drawing()) {
      this.drawing.set(false);
      this.rect.set(null);
    }
  }

  private pos(e: MouseEvent): { x: number; y: number } {
    const b = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const z = this.zoom();
    return { x: (e.clientX - b.left) / z, y: (e.clientY - b.top) / z };
  }

  removeZone(zone: MenuPdfZone) {
    this.zones.update(z => z.filter(z2 => z2.id !== zone.id));
    if (this.selId() === zone.id) this.selId.set(null);
  }

  assignDish(dish: DishOption) {
    const id = this.selId();
    if (!id) return;
    this.zones.update(z => z.map(zone =>
      zone.id === id
        ? { ...zone, dish_id: dish.id, dish_name: dish.name, dish_price: dish.base_price }
        : zone
    ));
    this.query.set('');
  }

  removeDish() {
    const id = this.selId();
    if (!id) return;
    this.zones.update(z => z.map(zone =>
      zone.id === id
        ? { ...zone, dish_id: null, dish_name: undefined, dish_price: undefined }
        : zone
    ));
  }

  selectZone(zoneId: string) { this.selId.set(zoneId); }

  zoneDotBg(zone: MenuPdfZone): string {
    return zone.dish_id ? 'var(--primary)' : 'var(--smoke-1)';
  }

  zoneItemBg(zoneId: string): string {
    return this.selId() === zoneId ? 'var(--smoke-2)' : 'transparent';
  }

  feedbackBorderColor(): string {
    return this.feedbackErr() ? 'var(--secondary)' : 'var(--tertiary)';
  }

  async saveAll() {
    this.saving.set(true);
    this.feedback.set(null);
    try {
      const saved: MenuPdfZone[] = [];
      for (const zone of this.zones()) {
        if (zone.id.startsWith('tmp_')) {
          const r = await this.arService.saveZone({
            menu_pdf_id: zone.menu_pdf_id,
            dish_id: zone.dish_id,
            page_number: zone.page_number,
            x: zone.x, y: zone.y,
            width: zone.width, height: zone.height,
          });
          if (r) saved.push({ ...r, dish_name: zone.dish_name, dish_price: zone.dish_price });
        } else {
          await this.arService.updateZone(zone.id, {
            dish_id: zone.dish_id,
            x: zone.x, y: zone.y,
            width: zone.width, height: zone.height,
          });
          saved.push(zone);
        }
      }
      if (this.pdf.status === 'uploading') {
        await this.arService.updatePdfStatus(this.pdf.id, 'ready');
      }
      this.zones.set(saved);
      this.feedback.set('✓ ' + saved.length + ' zone salvate');
      this.feedbackErr.set(false);
      this.zonesSaved.emit(saved);
      setTimeout(() => this.feedback.set(null), 3500);
    } catch {
      this.feedback.set('Errore nel salvataggio. Riprova.');
      this.feedbackErr.set(true);
    } finally {
      this.saving.set(false);
    }
  }
}